35	    const scenario = {
36	      customer: { yearsWithMHPCO: 0 },
37	      steps: [{
38	        op: "quote" as const,
39	        items: [
40	          { type: "rune" },
41	          { type: "rune" },
42	        ],
43	      }],
44	    };
