60	    const scenario = {
61	      customer: { yearsWithMHPCO: 0 },
62	      steps: [{
63	        op: "quote" as const,
64	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
65	      }],
66	    };
67	    const result = processScenario(scenario);
68	    expect(result).toEqual({ results: [{ premium: 105 }] });
69	  });
70	  it("calculates mixed components without block (2 runes + 1 moonstone = 75 G)", () => {
71	    const scenario = {
72	      customer: { yearsWithMHPCO: 0 },
73	      steps: [{
74	        op: "quote" as const,
75	        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
76	      }],
77	    };
78	    const result = processScenario(scenario);
79	    expect(result).toEqual({ results: [{ premium: 80 }] });
80	  });
81	  it("applies two separate blocks for 3 runes + 3 moonstones = 120 G", () => {
82	    const scenario = {
83	      customer: { yearsWithMHPCO: 0 },
84	      steps: [{
85	        op: "quote" as const,
86	        items: [
87	          { type: "rune" }, { type: "rune" }, { type: "rune" },
88	          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
89	        ],
90	      }],
91	    };
92	    const result = processScenario(scenario);
93	    expect(result).toEqual({ results: [{ premium: 125 }] });
94	  });
95	  it("sums base premiums for multiple different items in a policy", () => {
96	    const scenario = {
97	      customer: { yearsWithMHPCO: 0 },
98	      steps: [{
99	        op: "quote" as const,
100	        items: [
101	          { type: "sword", material: "steel", enchantment: 0, cursed: false },
102	          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
103	        ],
104	      }],
105	    };
106	    const result = processScenario(scenario);
107	    expect(result).toEqual({ results: [{ premium: 165 }] });
108	  });
109	
110	  // === QUOTE: Item-specific modifiers ===
111	  it("adds 50% cursed surcharge to the cursed item's base premium only", () => {
112	    const scenario = {
113	      customer: { yearsWithMHPCO: 0 },
114	      steps: [{
115	        op: "quote" as const,
116	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
117	      }],
118	    };
119	    const result = processScenario(scenario);
120	    expect(result).toEqual({ results: [{ premium: 155 }] });
121	  });
122	  it("adds 30% high-enchantment surcharge for enchantment level >= 5", () => {
123	    const scenario = {
124	      customer: { yearsWithMHPCO: 0 },
125	      steps: [{
126	        op: "quote" as const,
127	        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
