129	    };
130	    const result = processScenario(scenario);
131	    expect(result).toEqual({ results: [{ premium: 135 }] });
132	  });
133	  it.todo("applies both cursed and high-enchantment surcharges to same item");
134	  it.todo("applies item-specific surcharges only to affected items in multi-item policy");
135	
136	  // === QUOTE: Policy-wide modifiers ===
137	  it.todo("applies 10% first insurance surcharge to policy base premium");
138	  it.todo("applies 20% loyalty discount for customers with >= 2 years");
139	  it.todo("applies 15% follow-up discount on second and subsequent contracts");
140	  it.todo("combines all modifiers: newcomer with cursed sword = 165 G");
141	  it.todo("combines all modifiers: long-standing customer second contract cursed enchanted sword = 160 G");
142	
143	  // === QUOTE: Rounding ===
144	  it.todo("rounds premiums up (in MHPCO's favor)");
145	
146	  // === QUOTE: Errors ===
147	  it.todo("rejects unknown item type with non-zero exit");
148	
149	  // === CLAIM: Standard reimbursement ===
150	  it.todo("reimburses full damage minus 100 G deductible for regular item");
151	  it.todo("applies deductible per damaged item in multi-damage event");
152	  it.todo("reimburses component damage minus deductible");
153	
154	  // === CLAIM: Special clauses ===
155	  it.todo("reimburses enchantment >= 8 damage at 50% then deductible");
156	  it.todo("reimburses dragon material damage fully then deductible");
157	  it.todo("when both dragon and enchantment >= 8 apply, 50% rule wins then deductible");
158	  it.todo("dragon material with enchantment < 8 gets full reimbursement then deductible");
159	
160	  // === CLAIM: Cap ===
161	  it.todo("caps total payout at 2x insurance sum");
162	  it.todo("tracks remaining cap across multiple claims on same policy");
163	  it.todo("reduces payout to remaining cap when cap is nearly exhausted");
164	
165	  // === CLAIM: Errors ===
166	  it.todo("rejects damage to item not covered by policy");
167	  it.todo("rejects more damage entries of a type than policy covers");
168	  it.todo("rejects negative damage amount");
169	
170	  // === CLI integration ===
171	  it.todo("processes a full scenario with quote and claim steps via CLI JSON interface");
172	});
