1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const COMPONENT_TYPES = ["rune", "moonstone"];
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	
16	const isComponent = (item: any): boolean =>
17	  COMPONENT_TYPES.includes(item.type);
18	
19	const itemPremiumWithModifiers = (item: any): number => {
20	  const base = BASE_PREMIUMS[item.type] ?? 0;
21	  let premium = base;
22	  if (item.cursed) premium += base * 0.5;
23	  if (item.enchantment >= 5) premium += base * 0.3;
24	  return premium;
25	};
26	
27	const regularItemsPremium = (items: any[]): number =>
28	  items
29	    .filter((item: any) => !isComponent(item))
30	    .reduce((sum: number, item: any) => sum + itemPremiumWithModifiers(item), 0);
31	
32	const componentBlockPremium = (count: number, type: string): number =>
33	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
34	
35	const countByType = (items: any[]): Record<string, number> =>
36	  items.filter(isComponent).reduce(
37	    (acc: Record<string, number>, item: any) => ({
38	      ...acc,
39	      [item.type]: (acc[item.type] ?? 0) + 1,
40	    }),
41	    {},
42	  );
43	
44	const componentsPremium = (items: any[]): number =>
45	  Object.entries(countByType(items)).reduce(
46	    (sum, [type, count]) => sum + componentBlockPremium(count, type),
47	    0,
48	  );
49	
50	const calculateQuotePremium = (items: any[]): number =>
51	  regularItemsPremium(items) + componentsPremium(items) + PROCESSING_FEE;
52	
53	export function processScenario(scenario: any): any {
54	  const results = scenario.steps.map((step: any) => ({
55	    premium: calculateQuotePremium(step.items),
56	  }));
57	  return { results };
58	}
59

